var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"상대를 이해하기 위해 노력하는 것. 상대와 계속 함께 있고 싶다고 느끼는 것.","JPN":"相手を理解しようと努力すること。相手と永遠に共にいたいと思うこと。","ENG":"Trying to understand someone... Wanting to stay with them forever...","TWN":"努力去理解對方。感受到想要一直和對方在一起。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"단점. 그리고 장점…. 상대의 모든 것을 받아들이는 것…….","JPN":"短所、そして長所……相手のすべてを受け入れること……","ENG":"Flaws. And strengths... Accepting everything...","TWN":"缺點，還有優點……接受對方的一切……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"인간의 개념을 빌리자면, 그것은 <color=#ffd34c>사랑</color>이라고 해석됩니다.","JPN":"人間の概念を借りるなら、それは<color=#ffd34c>愛</color>と解釈できます。","ENG":"If I borrow the human concept, that is defined as <color=#ffd34c>love</color>.","TWN":"用人類的概念，那可以解釋為<color=#ffd34c>愛</color>。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그렇다면 저는 틀림없이 당신을 사랑하고 있는 것이겠죠.","JPN":"それなら私は間違いなく、あなたを愛しているのでしょう。","ENG":"Therefore, I must love you, Captain.","TWN":"那麼我一定是愛上你了吧。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사랑……!?","JPN":"愛……！？","ENG":"Love...?!","TWN":"愛！？"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 제가 내린 결론은 하나입니다.","JPN":"したがって、私はひとつの結論を出しました。","ENG":"Therefore, there is one conclusion I have reached.","TWN":"因此，我得出了一個結論。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신과 영원한 동기화를 희망합니다.","JPN":"あなたとの永遠なる同期化を希望します。","ENG":"I desire eternal synchronization with you.","TWN":"希望與你永遠同步。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"……함장.","JPN":"……艦長。","ENG":"...Captain.","TWN":"……艦長。"},"stage":{"bg":"MS_1403","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 그나저나 이거 곤란하게 됐군.","JPN":"ゴホン、それより困ったな。","ENG":"Ahem, in any case, this is quite the predicament.","TWN":"嗯，總之，這確實是個難題。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아시모프가 내린 시험을 통과하지 못하면, 꼼짝없이 프러포즈를 받게 생겼으니까.","JPN":"アシモフの試験を乗り越えられないと、プロポーズを受け入れざるを得なくなる。","ENG":"If I don't pass Asimov's trial, I'll end up receiving that proposal after all.","TWN":"如果我沒通過阿西莫夫的試煉，最後還是會被逼著接受那個提案。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"깡통 주제에 제법 로맨틱한 표현을 쓰긴 했지만, 사실상 전 인류의 목숨을 건 협박입니다.","JPN":"ボロ缶のくせになかなかロマンチックな表現を使いましたが、実際、あれは全人類の命をかけた脅迫ですからね。","ENG":"Junk Metal may have used romantic words, but it was basically a threat against all of humanity.","TWN":"鐵罐或許說得浪漫，但本質上就是對全人類的威脅。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우선은 그 시험인가 뭔가를 해결할 수밖에 없겠군요.","JPN":"まずはその試験だか何だかを解決するしかありません。","ENG":"For now, I suppose we have no choice but to deal with this so-called trial.","TWN":"眼下，我想我們只能硬著頭皮應付這所謂的試煉了。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 미나 양에게 연락을…….","JPN":"ではミナさんに連絡を……","ENG":"In that case, I should contact Mina...","TWN":"那麼聯絡米娜……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"발신자 제한이라고……?","JPN":"発信者番号非通知……？","ENG":"An unknown number...?","TWN":"不明來電……？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"안녕, 수연아? 잘 지냈어?","JPN":"やあ、キズナ。元気だった？","ENG":"Hello, Sooyeon. How have you been?","TWN":"你好，秀妍。你最近怎麼樣？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임 이후로 처음인가? 다친 데는 괜찮고?","JPN":"クリフォトゲーム以来初めてかな？　怪我の具合はどう？","ENG":"Is this the first time since the Qliphoth Game? Are your injuries healing well?","TWN":"這是自逆卡巴拉遊戲後第一次聯絡嗎？傷勢恢復得還好嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나, 나유빈……?","JPN":"い、イチノセ……？","ENG":"N-Na Yubin...?","TWN":"羅，羅瑜斌……？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네가 왜……?","JPN":"どうしてあなたが……？","ENG":"Why are you...?","TWN":"你怎麼會……？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 오래간만입니다.","JPN":"それから、お久しぶりです。","ENG":"And it's been a while, too.","TWN":"也好久不見了。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"때마침 곤란한 일을 겪고 계실 것 같아서, 무례를 무릅쓰고 먼저 연락드렸습니다.","JPN":"ちょうどお困りだろうと思って、無礼を承知で連絡さしあげました。","ENG":"I figured you'd be in some trouble, so I took the liberty of contacting you first.","TWN":"我覺得你可能遇到麻煩了，所以先主動聯絡了你。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……관리자님.","JPN":"……管理者さん。","ENG":"...Administrator.","TWN":"……管理者。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군…….","JPN":"なるほど……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 말대로라면, 그녀가 세피로트 나무의 파편으로 이루고자 하는 소원은…….","JPN":"君の話通りだとすると、彼女がセフィロトの破片で叶えようしている願いは……","ENG":"If what you say is true, then the wish she seeks to fulfill with the Fragment of the Tree of Sephiroth is...","TWN":"照你所說，她想藉由生命樹碎片實現的願望是……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 것을 처음으로 되돌리는 것. 즉, 고향 세계 런던의 부활이겠군.","JPN":"すべてを最初に戻すこと。つまり、故郷の世界のロンドンを復活させることだろうな。","ENG":"To return everything to the beginning. In other words, the restoration of her home world, London.","TWN":"將一切回溯至起點，也就是讓故鄉世界倫敦復活吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇습니다, 관리자님.","JPN":"そうです、管理者さん。","ENG":"That is correct, Administrator.","TWN":"正是如此，管理者。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이면세계를 원래대로 되돌리는 것. 그것이야 말로 모든 엑자일러의 염원일 테니까요.","JPN":"裏世界を元の姿に戻すこと。それこそが、すべてのエグザイラーの念願でしょうね。","ENG":"Restoring the Counterside to its original state. That is surely the wish of all Exiles.","TWN":"讓異界回歸原貌，那正是所有流浪者的夙願。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잠깐, 이면세계를 되돌린다고……?","JPN":"元の姿に戻す……？　裏世界を？","ENG":"Wait, restoring the Counterside...?","TWN":"等等，讓異界恢復原狀……？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 게 가능하다는 거야?","JPN":"そんなことが、本当に可能なの……？","ENG":"Is something like that even possible?","TWN":"真的有可能嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 불가능하다네.","JPN":"いや、不可能だ。","ENG":"No. It is impossible.","TWN":"不，不可能。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세피로트 나무에 현실을 개변할 힘이 잠들어 있다는 것은 사실이지만…….","JPN":"セフィロトが現実を改変する力を秘めていることは事実だが……","ENG":"It is true that the Tree of Sephiroth holds the power to alter reality, however...","TWN":"改變現實的力量的確沉睡於生命樹中……"},"stage":{"bg":"MS_1101_1","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"단순히 힘을 가지고 있는 것과 그것을 다룰 수 있는 능력은 전혀 별개의 문제야.","JPN":"単にその力を持っていることと、それを扱える能力があることとは全く別の問題だ。","ENG":"Simply possessing power and being able to wield it are entirely different matters.","TWN":"但擁有力量與能夠駕馭力量，完全是不同的問題。"},"stage":{"bg":"MS_1101_1","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론, 스완이라면 나름대로 비책을 생각해 두었을지도 모르지.","JPN":"もちろん、スワンなら彼女なりの秘策を用意しているかもしれないが……","ENG":"Of course, Swan may have devised her own contingency.","TWN":"當然，如果是史旺，或許已經準備了某種對策。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 한들, 이미 멸망해 버린 세계를 되돌릴 수 있다고 생각되지는 않아.","JPN":"だからといって、すでに滅んだ世界を蘇らせられるとは到底思えないな。","ENG":"Even so, I don't believe it's possible to restore a world that has already perished.","TWN":"即便如此，我仍不認為她能復原已經毀滅的世界。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 더욱 이해가 되지 않는군요.","JPN":"それなら尚更理解できませんね。","ENG":"Then I understand even less.","TWN":"那就更讓人難以理解了。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 완벽주의 여배우가 확실하지도 않은 도박수에 자기 목숨을 걸고 있다는 건가요?","JPN":"あの完璧主義の女優が、確証もない大博打に自分の命を懸けているということですか？","ENG":"Is that perfectionist actress really wagering her life on such an uncertain gamble?","TWN":"那位完美主義的女演員，竟然會為了一場毫無把握的賭局，賭上自己的性命嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니…….","JPN":"いいや……","ENG":"No...","TWN":"不……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무대 너머 관객들에게 그렇게 보여주고 싶은 거겠지.","JPN":"舞台の向こうの観客にそう見せたいのだろう。","ENG":"She likely wants the audience beyond the stage to see it that way.","TWN":"她只是想展現給舞台以外的觀眾而已。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관객들이라니……?","JPN":"観客……？","ENG":"The audience...?","TWN":"觀眾……？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아뇨, 그렇지는 않습니다.","JPN":"いいえ。そうではありません。","ENG":"No. Not really.","TWN":"沒有，不感興趣。"},"stage":{"bg":"CHARADE_003","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만……","JPN":"ですが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"CHARADE_003","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"방금 막 흥미가 생겼어요.","JPN":"たった今、興味が湧きました。","ENG":"I've taken an interest just now.","TWN":"剛剛突然開始感興趣了。"},"stage":{"bg":"CHARADE_003","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……글쎄요. 저는 그저 응원하고 있을 뿐이랍니다.","JPN":"……さあ。私はただ応援がしたいだけなんです。","ENG":"...Well. I was merely rooting for you.","TWN":"……怎麼說呢，我只是為你們加油而已。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"팬이니까요. 당신의.","JPN":"ファンですから。あなたの。","ENG":"Because I am a fan. Of yours.","TWN":"因為我是你的粉絲。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 전 당신의 열렬한 관중이자 팬입니다.","JPN":"そうです。私はあなたの熱烈な観客であり、ファンなのです。","ENG":"Yes. I am your biggest fan and audience.","TWN":"沒錯，我是你最忠實的觀眾和粉絲。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 언젠가 제 무대에 당신을 초청하고 싶었어요.","JPN":"いつかあなたを私の舞台に招待したかった。","ENG":"Which is why I was meaning to invite you to my performance one day.","TWN":"所以總有一天想把你邀請到我的舞台。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마침내, 제가 준비한 각본을 실현할 기회가 온 셈이죠.","JPN":"そしてやっと今、私の準備した脚本を実現するチャンスが来たのです。","ENG":"And finally, I have the chance to carry out my script.","TWN":"而我終於迎來了實現自己寫的劇本的機會。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게까지 해서 나에게 뭘 보여주고 싶은 거지?","JPN":"そこまでして私に見せたいものとは何かね？","ENG":"So, what are you trying to show me by going through all this?","TWN":"你費這麼大勁是想給我看什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 불가능하다 여겨 포기했던 일을… 실현해 보일 겁니다.","JPN":"あなたが不可能だと思い、諦めたことを……私が実現させてみせます。","ENG":"I will accomplish... what you deemed impossible and gave up on.","TWN":"你將實現……你認為不可能實現的事情。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 부디, 당신이 이 극의 종장에 무사히 다다를 수 있기를…","JPN":"だから、どうかあなたがこの物語の終章に無事たどり着けるよう……","ENG":"So I sincerely hope you reach the finale of this play...","TWN":"所以，希望你能平安活到這個劇本的大結局……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>팬으로서 응원할게요.</color>","JPN":"<color=#ffd34c>ファンとして応援します。</color>","ENG":"<color=#ffd34c>As a fan.</color>","TWN":"<color=#ffd34c>我會作為粉絲為你加油。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들은 모를 테죠.","JPN":"あなたたちにはわからないのです。","ENG":"You do not know.","TWN":"你們不會知道的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타기리온이 거쳐간 세계가 얼마나 허무하게 무너졌는지.","JPN":"タギリオンが経てきた世界がどんなに虚しく崩れてしまったのか。","ENG":"How the worlds Thagirion passed through collapsed in vain.","TWN":"塔基里翁走過的世界是多麼空虛地瓦解了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 무수한 노력에도, 내일을 빼앗기고 만 세계가 얼마나 처참했는지.","JPN":"計り知れない努力にも関わらず、明日を奪われてしまった世界の末路がどれだけ悲惨なのか。","ENG":"Despite their countless efforts, how miserable the world was after its future was taken away.","TWN":"付出無數的努力後仍然被奪走希望的世界是多麼地悲慘。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 날을 돌려받기 위해서라면…","JPN":"その日々を返してもらうためには……","ENG":"I'll do whatever it takes...","TWN":"為了找回那一天……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…난 수단과 방법을 가리지 않을 겁니다.","JPN":"……私はどんな手段でも使います。","ENG":"...to take back that day.","TWN":"……我會不惜一切代價。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"계약을 했거든요.","JPN":"契約をしたんです。","ENG":"I signed a contract.","TWN":"因為我約定好了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 세계를 바치는 대가로, 그녀의 소원은 내가 갖기로 말이죠.","JPN":"この世界を捧げる代わりに、彼女の願いを私がもらうと。","ENG":"In return for offering this world, I would get the rights to her wish.","TWN":"作為獻出這個世界的代價，我會得到她的願望。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아이러니하군.","JPN":"皮肉なものだな。","ENG":"How ironic.","TWN":"真諷刺。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자기 세계를 멸망시킨 자에게 희망을 맡기다니 말이야.","JPN":"自分の世界を滅ぼした相手に、希望を託すとは。","ENG":"Leaving hope to the one who destroyed your own world.","TWN":"把希望寄託在毀滅自己世界的人身上。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이해 받길 원했다면 이런 일은 시작하지도 않았겠죠.","JPN":"理解して欲しいと思うなら、こんなことは最初からやりません。","ENG":"If I wanted to be understood, I would not have started this in the first place.","TWN":"如果是為了得到理解，我就不會這樣做了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원하는 것이 있으면 원수와도 손을 잡는다… 참 단순한 심리로군.","JPN":"望むものがあるなら、仇とも手を組む……まったく単純な思考だな。","ENG":"Getting in bed with the enemy to get what you want... Quite simple.","TWN":"為了目的甘願與仇人聯手……真是單純。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네가 노엘 양에게 보여준 광경은 그리 단순한 사연이 아닌 것 같던데.","JPN":"だが君がノエル君に見せた光景はそんな単純な話ではないと思うのだが。","ENG":"However, what you showed Noelle didn't seem like such a simple tale.","TWN":"但你給洛艾兒展現的場景似乎並沒有那麼單純。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임은 <color=#ffd34c>어떤 존재</color>에 의해 이뤄지는 것.","JPN":"クリフォトゲームは<color=#ffd34c>ある存在</color>によって行われるもの。","ENG":"The Qliphoth Game is created by a <color=#ffd34c>certain being</color>.","TWN":"逆卡巴拉遊戲依託於<color=#ffd34c>某種存在</color>。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 모든 것이 <color=#ffd34c>그 존재</color>가 만들어낸 규칙에 갇혀 있진 않아요.","JPN":"しかし、全てが<color=#ffd34c>その存在</color>が作ったルールに縛られているわけではありません。","ENG":"But not everything is bound by the rules <color=#ffd34c>this being</color> makes.","TWN":"但並非一切都受困於由<color=#ffd34c>那個存在</color>創造的規矩中。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 일전에 드렸던 경고를 부디 기억하고 계신다면 좋겠네요.","JPN":"私が以前差し上げた警告を、どうか覚えていて欲しいですね。","ENG":"I hope you still remember the warning I gave you last time.","TWN":"希望你還記得我不久前給你的警告。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"커튼콜은 여기까지.","JPN":"カーテンコールはここまで。","ENG":"This is where the curtain call ends.","TWN":"這齣戲就此謝幕。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임의 막이 열리는 날, 다시 뵙도록 하죠.","JPN":"クリフォトゲームの幕が上がるその日に、またお会いしましょう。","ENG":"We shall meet again when the Qliphoth Game begins.","TWN":"逆卡巴拉遊戲拉開序幕的那一天，我們再見吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금까지 스완의 행적을 돌이켜 보면…….","JPN":"今までのスワンの足取りを振り返ってみると……","ENG":"Looking back on Swan's actions thus far...","TWN":"回顧史旺至今的行動……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 그녀 자신은 세계를 되돌리는 것이 가능하다고 믿고 있을지도 모르지.","JPN":"彼女は本当に、世界を元に戻すことが可能だと信じているのかもしれない。","ENG":"It may be that she herself truly believes restoring the world is possible.","TWN":"或許，她其實深信能夠逆轉世界。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이로 인해, 그녀가 목숨을 건 도박수를 행하고 있는 것도 사실이야.","JPN":"それが理由で、彼女が命を懸けた大博打に出ていることも事実だ。","ENG":"That is why she is indeed making a life-or-death gamble.","TWN":"因此，她賭上性命也是事實。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 어째선지 그녀의 각본에는 다른 의도가 깔려있다는 생각이 드는군.","JPN":"しかしどうも、彼女の脚本には別の意図が隠れている気がしてならない。","ENG":"However, for some reason, I sense another intention beneath her script.","TWN":"但不知為何，我總覺得她的劇本另有意圖。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다도, 훌륭한 연기자는 자기 자신마저도 속인다고 하지 않나?","JPN":"何より、立派な役者は自分自身さえも騙すというじゃないか。","ENG":"After all, isn't it said that a great actor even deceives themselves?","TWN":"畢竟不是有句話說，優秀的演員連自己都能騙嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지수씨의 도움을 받은 것도 아닌데, 단편적인 정보로 거기까지 추측하사다니…….","JPN":"シノさんの手を借りたわけでもないのに、断片的な情報だけでそこまで突き止めるとは……","ENG":"To deduce that much from fragmentary information, without Jisoo's help...","TWN":"沒有依靠智秀小姐的協助，僅憑零碎資訊就能推測到那裡……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"과연 당신은 대단한 사람이군요, 관리자님.","JPN":"さすがです、管理者さん。","ENG":"You truly are impressive, Administrator.","TWN":"您果然是位了不起的人呢，管理者。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저 역시 당신과 같은 의견입니다.","JPN":"僕もあなたと同意見です。","ENG":"I share your opinion as well.","TWN":"我跟您看法相同。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"틀림없이 스완은 아직 <color=#ffd34c>퍼즐 조각</color>을 감추고 있어요.","JPN":"間違いなく、スワンはまだ<color=#ffd34c>パズルのピース</color>を隠しています。","ENG":"Without a doubt, Swan is still hiding a <color=#ffd34c>piece of the puzzle</color>.","TWN":"史旺一定還藏著<color=#ffd34c>拼圖碎片</color>。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 조각은 그녀 자신만이 알고 있는 어딘가에 꼭꼭 숨겨두었겠죠.","JPN":"そのピースは彼女のみが知るどこかに隠ぺいしておいたはず。","ENG":"That piece is surely hidden away somewhere only she knows.","TWN":"那塊碎片，一定被她藏在只有她自己知道的某個地方。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"언젠가 그 마지막 조각을 끼워줄 사람을 간절히 기다리면서…….","JPN":"いつかその最後のピースをはめてくれる人を待ちわびながら……","ENG":"Waiting earnestly for the one who will one day fit in the final piece...","TWN":"一邊殷切期盼著能將最後一塊拼上的那個人……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"そうか。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"퍼즐 조각이라…….","JPN":"パズルのピース……","ENG":"A piece of the puzzle...","TWN":"拼圖碎片啊……"},"stage":{"bg":"MAINSTREAM_000005","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 추측에 그곳은 <color=#ffd34c>스완의 모든 각본이 시작된 곳</color>…….","JPN":"僕の推測だと、そこは<color=#ffd34c>スワンのすべての脚本が始まった場所</color>……","ENG":"My guess is that place is <color=#ffd34c>where all of Swan's scripts began</color>...","TWN":"依我推測，那個地方是<color=#ffd34c>史旺所有劇本的起點</color>……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아마도 당신이라면, 그곳이 어디인지 짐작하고 계시겠죠?","JPN":"あなたなら、心当たりがあるんじゃないですか？","ENG":"If it's you, you likely already have an idea where that might be, don't you?","TWN":"我想若是您，應該已經猜到是哪裡了吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럼, 슬슬 움직이도록 하죠.","JPN":"では、そろそろ動きましょうか。","ENG":"Then let's begin moving.","TWN":"那麼我們也差不多該行動了。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스완의 고향 세계는 고심도의 이면세계입니다.","JPN":"スワンの故郷の世界は高深度の裏世界です。","ENG":"Swan's home world is the hyperdepths of the Counterside.","TWN":"史旺的故鄉世界，位於高深度異界。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"미나 양이 그곳에 다다를 수 있도록, 제 동료와 글레입니르를 빌려드리죠.","JPN":"ミナさんがそこにたどり着けるよう、僕の仲間とグレイプニルを貸して差し上げます。","ENG":"I will lend you my colleagues and Gleipnir, so that Mina may reach it.","TWN":"為了讓米娜抵達那裡，我會借你我的同伴與格萊伊尼勒。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아, 그건 원래 당신의 함선이었으니, 빌려드린다는 말은 어폐가 있네요.","JPN":"あ、もともとあなたの艦船だし、貸すという表現はやや語弊がありますね。","ENG":"Ah, since it was originally your ship, saying I'm lending it may be inaccurate.","TWN":"啊，那原本就是你的艦船，說「借你」似乎不太對呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"글레입니르라고? 그걸 네가 어떻게……?","JPN":"グレイプニル？　なぜあなたがそれを……？","ENG":"Gleipnir? How do you...?","TWN":"格萊伊尼勒？那你怎麼會……？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"글쎄, 수연아?","JPN":"なぜだろうね？　キズナ。","ENG":"Well, Sooyeon?","TWN":"怎麼樣，秀妍？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이쯤 되면, 내가 그걸 어떻게 가지고 있는지 짐작할 수 있지 않아?","JPN":"ここまで来ると、なぜ僕がそれを持っているか、わかるんじゃない？","ENG":"At this point, can't you guess how I came to have it?","TWN":"都到這個地步了，你還猜不到我是怎麼得到它的嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何ですって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이거 참 기대가 되는데요?","JPN":"いやあ、楽しみですね。","ENG":"This is getting exciting.","TWN":"真讓人期待吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"오랜 각본의 끝에서, 결국에는 두 사람이 재회하게 될 테니까요.","JPN":"悠久なる脚本の終盤で、ついに二人が再会を果たすわけですから。","ENG":"At the end of this long-running script, the two of them will finally reunite.","TWN":"在這漫長劇本的終點，兩人終於重逢。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"相同一時間"},"stage":{"bg":"BLACK","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역","JPN":"シャレード～ロータス管理警戒区域","ENG":"Charade-Lotus Perimeter Zone","TWN":"查雷德～洛德斯管理警戒區域"},"stage":{"bg":"BLACK","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"조금만 기다려, 노엘.","JPN":"あと少しだけ待ってて、ノエル。","ENG":"Just hold on a little longer, Noelle.","TWN":"稍等一下，洛艾兒。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 반드시 구하러 갈 테니까…….","JPN":"私が必ず助けに行くから……","ENG":"I will save you...","TWN":"我一定會去救你的……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"이야~ 이제야 도착한 거야?","JPN":"いや～やっと着いたの？","ENG":"Well, well. Look who finally got here.","TWN":"哇～現在才到嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"조금만 더 빨리 오지 그랬어? 기다리느라 심심해서 죽는 줄 알았다니깐~?","JPN":"もうちょっと早く来てくれればよかったのに。待ってる間暇で暇で～","ENG":"Couldn't you have shown up a bit sooner? I was bored out of my mind waiting!","TWN":"怎麼不早點來呢？等得我都快無聊死了～"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너는……?","JPN":"あなた……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 네가 왜 여기에 있어……?","JPN":"ちょっと、なんであなたがここに……？","ENG":"Wait, what are you doing here...?","TWN":"等一下，你為什麼會在這裡……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하아… 예상하긴 했지만 이거 섭섭하네.","JPN":"はあ……予想はしてたけど、寂しいもんね。","ENG":"*Sigh* I kinda expected this, but still, it stings.","TWN":"哈……雖然我預料到了，但還是有點失望啊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마, 그 실눈 녀석이랑 너희 소대장… 둘 다 나에 대해서 아무 말도 안 해준 거야?","JPN":"まさか、あの糸目とあんたの小隊長……2人ともあたしについて言ってくれなかったわけ？","ENG":"So neither your commander nor the squinty one told you a single thing about me...?","TWN":"難道，那位眯眯眼和你們的小隊長……都沒有告訴你們關於我的事情嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미……?","JPN":"エイミー……？","ENG":"Amy...?","TWN":"艾米……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너, 정말로 에이미 맞아……?","JPN":"あなた、本当にエイミーなの……？","ENG":"Are you... really Amy...?","TWN":"你，真的是艾米嗎……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};